import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';

const Medicines = () => {
  const { t } = useTranslation();
  const [medicines, setMedicines] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  // Dummy data for demonstration
  const dummyMedicines = [
    {
      id: '1',
      name: 'Paracetamol 500mg',
      generic_name: 'Acetaminophen',
      manufacturer: 'Cipla Ltd',
      price: 25.50,
      stock_quantity: 150,
      expiry_date: '2025-12-31',
      category: 'Pain Relief',
      description: 'Pain reliever and fever reducer',
      requires_prescription: false
    },
    {
      id: '2',
      name: 'Amoxicillin 250mg',
      generic_name: 'Amoxicillin',
      manufacturer: 'Sun Pharma',
      price: 85.00,
      stock_quantity: 8,
      expiry_date: '2024-08-15',
      category: 'Antibiotics',
      description: 'Antibiotic for bacterial infections',
      requires_prescription: true
    },
    {
      id: '3',
      name: 'Cetirizine 10mg',
      generic_name: 'Cetirizine HCl',
      manufacturer: 'Dr. Reddy\'s',
      price: 45.00,
      stock_quantity: 0,
      expiry_date: '2025-03-20',
      category: 'Antihistamines',
      description: 'Allergy relief medication',
      requires_prescription: false
    },
    {
      id: '4',
      name: 'Metformin 500mg',
      generic_name: 'Metformin HCl',
      manufacturer: 'Lupin',
      price: 120.00,
      stock_quantity: 75,
      expiry_date: '2025-11-10',
      category: 'Diabetes',
      description: 'Type 2 diabetes management',
      requires_prescription: true
    },
    {
      id: '5',
      name: 'Omeprazole 20mg',
      generic_name: 'Omeprazole',
      manufacturer: 'Ranbaxy',
      price: 65.00,
      stock_quantity: 5,
      expiry_date: '2024-12-05',
      category: 'Gastric',
      description: 'Proton pump inhibitor for acid reflux',
      requires_prescription: true
    },
    {
      id: '6',
      name: 'Vitamin D3 60000 IU',
      generic_name: 'Cholecalciferol',
      manufacturer: 'Abbott',
      price: 95.00,
      stock_quantity: 200,
      expiry_date: '2026-01-15',
      category: 'Vitamins',
      description: 'Vitamin D supplement',
      requires_prescription: false
    }
  ];

  useEffect(() => {
    fetchMedicines();
  }, []);

  const fetchMedicines = async () => {
    try {
      setLoading(true);
      // For demo purposes, we'll use dummy data
      // In production, uncomment the API call below
      // const response = await medicineAPI.getAll();
      // setMedicines(response.data);
      
      // Simulate API delay
      setTimeout(() => {
        setMedicines(dummyMedicines);
        setLoading(false);
      }, 1000);
    } catch (error) {
      console.error('Error fetching medicines:', error);
      setError('Failed to load medicines');
      setMedicines(dummyMedicines); // Fallback to dummy data
      setLoading(false);
    }
  };

  // Icons removed: text-only indicators will be used

  const filteredMedicines = medicines.filter(medicine => {
    const term = searchTerm.toLowerCase();
    return (
      medicine.name.toLowerCase().includes(term) ||
      (medicine.generic_name || '').toLowerCase().includes(term) ||
      (medicine.id || '').toLowerCase().includes(term)
    );
  });

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-IN');
  };

  // No icons or badges; keep text-only presentation

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center min-h-64">
          <div className="loading"></div>
          <span className="ml-2">Loading medicines...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-bg-secondary">
      {/* Header - Match Home theme */}
      <div className="bg-gradient-to-r from-primary-color to-primary-dark text-white py-12">
        <div className="container mx-auto px-6 text-center">
          <h1 className="text-4xl font-black mb-2 tracking-tight">
            {t('medicines')} <span className="text-primary-light">Inventory</span>
          </h1>
          <p className="text-primary-light">Real-time medicine stock and availability</p>
        </div>
      </div>

      <div className="container mx-auto px-6 py-8 pb-40">
        {/* Search only (text-only, no icons) */}
        <div className="card-elevated mb-6 max-w-3xl mx-auto">
          <label className="block text-sm font-semibold text-text-primary mb-1">Search medicines</label>
          <input
            type="text"
            placeholder="Search medicines..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="input"
          />
        </div>

        {/* Error Message */}
        {error && (
          <div className="bg-red-100 border border-red-300 text-red-700 p-4 rounded-lg mb-6">
            {error}
          </div>
        )}

        {/* Medicines Table - Text-only columns */}
        <div className="card-elevated overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full table-fixed text-sm border border-gray-200" style={{ borderCollapse: 'collapse' }}>
              <colgroup>
                <col style={{ width: '44%' }} />
                <col style={{ width: '18%' }} />
                <col style={{ width: '18%' }} />
                <col style={{ width: '20%' }} />
              </colgroup>
              <thead className="bg-gray-50">
                <tr>
                  <th className="text-left p-3 text-sm font-semibold text-text-primary border border-gray-200">Medicine Name</th>
                  <th className="text-center p-3 text-sm font-semibold text-text-primary border border-gray-200">ID / Code</th>
                  <th className="text-center p-3 text-sm font-semibold text-text-primary border border-gray-200">Stock</th>
                  <th className="text-center p-3 text-sm font-semibold text-text-primary border border-gray-200">Expiry</th>
                </tr>
              </thead>
              <tbody>
                {filteredMedicines.map((medicine) => (
                  <tr key={medicine.id} className="hover:bg-gray-50">
                    <td className="p-3 align-top break-words border border-gray-200">
                      <div className="font-medium text-text-primary leading-snug">{medicine.name}</div>
                      {medicine.generic_name && (
                        <div className="text-xs text-text-secondary mt-0.5 leading-tight">{medicine.generic_name}</div>
                      )}
                    </td>
                    <td className="p-3 align-top text-center border border-gray-200">
                      <div className="text-text-primary inline-block min-w-[1.5rem]">{medicine.id}</div>
                    </td>
                    <td className="p-3 text-center align-top border border-gray-200">
                      <span className={`text-xs font-medium ${medicine.stock_quantity > 0 ? 'text-green-700' : 'text-red-700'}`}>
                        {medicine.stock_quantity > 0 ? 'In Stock' : 'Out of Stock'}
                      </span>
                    </td>
                    <td className="p-3 text-center align-top border border-gray-200">
                      <span className="text-xs text-text-secondary">{formatDate(medicine.expiry_date)}</span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Results Summary / Empty State */}
        {filteredMedicines.length === 0 && (
          <div className="text-center py-12 text-text-secondary">No medicines found</div>
        )}
        {filteredMedicines.length > 0 && (
          <div className="mt-6 text-center text-text-secondary text-sm">
            Showing {filteredMedicines.length} of {medicines.length} medicines
          </div>
        )}
      </div>
    </div>
  );
};

export default Medicines;
